# tests/integration/test_llm_calls.py
import pytest
from pytest_recording import record   # vcrpy-based plugin
from myagent.llm_client import LLMClient

@pytest.fixture
def client():
    return LLMClient(model="gpt-4o-mini", timeout=10)

@pytest.mark.vcr()   # replays cassette/test_llm_calls/calls_search_tool.yaml
def test_llm_calls_search_tool_on_factual_query(client):
    messages = [{"role": "user", "content": "What is the boiling point of water?"}]
    response = client.chat(messages, tools=client.all_tools())
    assert response.stop_reason in ("tool_use", "end_turn")
    if response.stop_reason == "tool_use":
        tool_call = response.tool_calls[0]
        assert tool_call.function.name == "search"
        args = json.loads(tool_call.function.arguments)
        assert "query" in args

@pytest.mark.vcr()
def test_llm_returns_structured_json_for_summarize(client):
    from myagent.tasks import summarize_task
    result = summarize_task(client, text="The quick brown fox jumps over the lazy dog.")
    assert isinstance(result, dict)
    assert "summary" in result
    assert len(result["summary"]) > 0

# tests/e2e/scenarios/test_research_workflow.py
import pytest
from myagent.agent import ResearchAgent

@pytest.mark.e2e
@pytest.mark.timeout(120)
def test_research_agent_produces_cited_answer(staging_config):
    agent = ResearchAgent(config=staging_config)
    result = agent.run("Summarize the key findings of the IPCC AR6 report on sea level rise.")

    assert result.status == "completed"
    assert len(result.citations) >= 1
    assert result.turn_count <= 10, "Agent should not exceed 10 turns"
    assert "sea level" in result.answer.lower()

@pytest.mark.e2e
@pytest.mark.timeout(60)
def test_agent_handles_ambiguous_query_with_clarification(staging_config):
    agent = ResearchAgent(config=staging_config)
    result = agent.run("Tell me about Python.")
    # Agent must either clarify or produce an answer that names a specific
    # interpretation (language vs. snake)
    assert result.status in ("completed", "awaiting_clarification")
